using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// --- 1. GetTypeInfo<T>(): strongly-typed metadata retrieval ---
var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person> => Type={personInfo.Type.Name}, Kind={personInfo.Kind}");

string json = JsonSerializer.Serialize(new Person("Ada", 36), personInfo);
Console.WriteLine($"Serialized: {json}");

// --- 2. TryGetTypeInfo<T>(): check-without-throwing ---
// Works: the default resolver knows about List<int>
if (options.TryGetTypeInfo<List<int>>(out var listInfo))
    Console.WriteLine($"TryGet List<int> => resolved ({listInfo!.Type})");
else
    Console.WriteLine("TryGet List<int> => NOT resolved");

// Does NOT throw: the source-gen-only context below has no metadata for Person
var limited = new JsonSerializerOptions { TypeInfoResolver = EmptyContext.Default };

if (limited.TryGetTypeInfo<Person>(out var missing))
    Console.WriteLine($"TryGet Person (limited) => resolved ({missing!.Type.Name})");
else
    Console.WriteLine("TryGet Person (limited) => NOT resolved (safe, no exception)");

// ----- types -----
public record Person(string Name, int Age);

[JsonSerializable(typeof(int))]          // only int — deliberately no Person
public partial class EmptyContext : JsonSerializerContext;

